import React, { useState, useEffect } from 'react';
import Button from '@mui/material/Button';
import DeleteIcon from '@mui/icons-material/Delete';
import EditIcon from '@mui/icons-material/Edit';

function Pets() {
  const [isLoaded, setIsLoaded] = useState(false);
  const [pets, setPets] = useState([]);
  const [formInputs, setFormInputs] = useState({
    animal: '',
    description: '',
    age: '',
    price: ''
  });
  const [editingPetId, setEditingPetId] = useState(null);

  useEffect(() => {
    fetchPets();
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormInputs(inputs => ({ ...inputs, [name]: value }));
  };

  function fetchPets() {
    // Your fetchPets logic
  }

  function addOrUpdatePet() {
    const action = editingPetId ? 'update' : 'add';
    const url = `http://localhost:3001/api?act=${action}&${editingPetId ? 'id=' + editingPetId + '&' : ''}animal=${formInputs.animal}&description=${formInputs.description}&age=${formInputs.age}&price=${formInputs.price}`;
    
    fetch(url)
      .then(res => res.json())
      .then(() => {
        fetchPets();
        setFormInputs({ animal: '', description: '', age: '', price: '' });
        if (action === 'update') setEditingPetId(null);
      });
  }

  function startEdit(pet) {
    setFormInputs({ animal: pet.animal, description: pet.description, age: pet.age.toString(), price: pet.price.toString() });
    setEditingPetId(pet.id);
  }

  function cancelEdit() {
    setFormInputs({ animal: '', description: '', age: '', price: '' });
    setEditingPetId(null);
  }

  return (
    <div>
      {!isLoaded ? <div>Loading...</div> : (
        <>
          {/* Pet Table */}
          {/* Map through pets and display them */}

          {/* Form for adding/updating a pet */}
          <div>
            <input name="animal" value={formInputs.animal} onChange={handleInputChange} placeholder="Animal" />
            <input name="description" value={formInputs.description} onChange={handleInputChange} placeholder="Description" />
            <input name="age" value={formInputs.age} onChange={handleInputChange} placeholder="Age" />
            <input name="price" value={formInputs.price} onChange={handleInputChange} placeholder="Price" />
            <Button onClick={addOrUpdatePet}>{editingPetId ? 'Update' : 'Add'} Pet</Button>
            {editingPetId && <Button onClick={cancelEdit}>Cancel</Button>}
          </div>
        </>
      )}
    </div>
  );
}

export default Pets;
